{"code": "import json
import re
from collections import defaultdict

# Read the full clinical data file
clinical_file = locals()['var_functions.query_db:24']
with open(clinical_file, 'r') as f:
    clinical_data = json.load(f)

# Read the CDH1 mutation data file
mutation_file = locals()['var_functions.query_db:34']
with open(mutation_file, 'r') as f:
    mutation_data = json.load(f)

# Create patient mapping with barcode and histological type
patient_data = {}
for record in clinical_data:
    desc = record['Patient_description']
    # Look for TCGA-XX-XXXX pattern
    match = re.search(r'TCGA-[A-Z0-9]{2}-[A-Z0-9]{4}', desc)
    if match:
        barcode = match.group(0)
        histology = record['histological_type']
        if histology and histology != 'null' and histology != '':
            patient_data[barcode] = histology

# Get all patients with CDH1 mutations (PASS filter)
cdh1_mutated_patients = set()
for record in mutation_data:
    cdh1_mutated_patients.add(record['ParticipantBarcode'])

# Create contingency table (histology vs CDH1 mutation status)
contingency_table = defaultdict(lambda: {'mutated': 0, 'not_mutated': 0})

for barcode, histology in patient_data.items():
    if barcode in cdh1_mutated_patients:
        contingency_table[histology]['mutated'] += 1
    else:
        contingency_table[histology]['not_mutated'] += 1

# Calculate marginal totals (row and column totals)
row_totals = {}
for histology, counts in contingency_table.items():
    row_totals[histology] = counts['mutated'] + counts['not_mutated']

# Calculate column totals
col_totals = {'mutated': 0, 'not_mutated': 0}
for histology, counts in contingency_table.items():
    col_totals['mutated'] += counts['mutated']
    col_totals['not_mutated'] += counts['not_mutated']

grand_total = sum(row_totals.values())

# Filter out categories with row totals <= 10
filtered_table = {}
for histology, total in row_totals.items():
    if total > 10:
        filtered_table[histology] = contingency_table[histology]

print('__RESULT__:')
print(json.dumps({
    'original_histologies': len(contingency_table),
    'filtered_histologies': len(filtered_table),
    'contingency_table': dict(filtered_table),
    'row_totals': {h: r for h, r in row_totals.items() if h in filtered_table},
    'col_totals': col_totals,
    'grand_total': grand_total
}, indent=2))"}

