import math

# Get the data from previous result
data = locals()['var_functions.execute_python:40']
contingency_table = data['contingency_table']
row_totals = data['row_totals']
col_totals = data['col_totals']
grand_total = data['grand_total']

# Calculate expected frequencies and chi-square statistic
chi_square = 0
expected_table = {}
obtained_table = {}

for histology in contingency_table:
    expected_table[histology] = {}
    obtained_table[histology] = {}

    row_total = row_totals[histology]

    for status in ['mutated', 'not_mutated']:
        col_total = col_totals[status]
        observed = contingency_table[histology][status]
        expected = (row_total * col_total) / grand_total

        expected_table[histology][status] = expected
        obtained_table[histology][status] = observed

        if expected > 0:
            chi_square += ((observed - expected) ** 2) / expected

print('__RESULT__:')
print(json.dumps({
    'chi_square_statistic': chi_square,
    'expected_frequencies': expected_table,
    'observed_frequencies': obtained_table,
    'degrees_of_freedom': (len(contingency_table) - 1) * (2 - 1)
}, indent=2))"}

